import React, { useEffect, useState } from "react"
import { Flex, Box } from "rebass"
import { graphql, navigate } from "gatsby"
import { Fade } from "react-reveal"

import { StandardLayout } from "../components/Layout"
import { Brother, LeaderBrother } from "../components/Brother"
import FamilyTree from "../components/FamilyTree/FamilyTree"
import CenterHeader from "../components/CenterHeader"
import { Helmet } from "react-helmet"

const TAB_IDS = ["brothers", "executive", "directors", "family"]

const TAB_LABELS = {
  brothers: "Brothers",
  executive: "Executive Committee",
  directors: "Directors",
  family: "Family Trees",
}

const ACCENT = "#9284cf"
const ACCENT_SOFT = "rgba(146, 132, 207, 0.15)"

function tabFromSearch(search) {
  if (!search) return null
  const t = new URLSearchParams(search).get("tab")
  return TAB_IDS.includes(t) ? t : null
}

const sortedBrothers = (nodes) =>
  nodes
    .filter((b) => b.First_Name !== "InsertFirstName")
    .sort((a, b) =>
      a.Last_Name > b.Last_Name
        ? 1
        : b.Last_Name > a.Last_Name
        ? -1
        : a.First_Name > b.First_Name
        ? 1
        : b.First_Name > a.First_Name
        ? -1
        : 0
    )

export default ({ data, location }) => {
  const initialTab = tabFromSearch(location?.search) || "brothers"
  const [activeTab, setActiveTab] = useState(initialTab)

  useEffect(() => {
    const t = tabFromSearch(location?.search)
    setActiveTab(t || "brothers")
  }, [location?.search])

  const goToTab = (tabId) => {
    setActiveTab(tabId)
    const path = `${location?.pathname || "/brothers"}?tab=${tabId}`
    navigate(path, { replace: true })
  }

  const onTabKeyDown = (e, index) => {
    if (e.key === "ArrowRight" || e.key === "ArrowLeft") {
      e.preventDefault()
      const next =
        e.key === "ArrowRight"
          ? (index + 1) % TAB_IDS.length
          : (index - 1 + TAB_IDS.length) % TAB_IDS.length
      goToTab(TAB_IDS[next])
      document.getElementById(`brothers-tab-${TAB_IDS[next]}`)?.focus()
    }
  }

  const brothersList = sortedBrothers(data.brothers.nodes)

  return (
    <StandardLayout>
      <Helmet>
        <title>Brothers | Delta Sigma Pi - Pi Sigma Chapter</title>
        <meta
          name="Delta Sigma Pi - Pi Sigma Chapter Brothers Page"
          content="Delta Sigma Pi - Pi Sigma Chapter Brothers Page"
        />
      </Helmet>

      <Fade>
        <CenterHeader>{TAB_LABELS[activeTab]}</CenterHeader>
      </Fade>

      <Box
        as="div"
        role="tablist"
        aria-label="Brothers page sections"
        sx={{
          display: "flex",
          flexDirection: "row",
          flexWrap: "wrap",
          justifyContent: "center",
          alignItems: "center",
          gap: "10px",
          width: "100%",
          maxWidth: "100%",
          marginBottom: "36px",
          paddingBottom: "8px",
          overflowX: "auto",
          WebkitOverflowScrolling: "touch",
        }}
      >
        {TAB_IDS.map((id, index) => {
          const selected = activeTab === id
          return (
            <button
              key={id}
              type="button"
              role="tab"
              id={`brothers-tab-${id}`}
              aria-selected={selected}
              aria-controls={`brothers-panel-${id}`}
              tabIndex={selected ? 0 : -1}
              onClick={() => goToTab(id)}
              onKeyDown={(e) => onTabKeyDown(e, index)}
              style={{
                fontFamily: "Lato, sans-serif",
                fontSize: "16px",
                fontWeight: selected ? 600 : 500,
                padding: "10px 18px",
                borderRadius: "8px",
                border: selected ? `2px solid ${ACCENT}` : `2px solid ${ACCENT}`,
                cursor: "pointer",
                flex: "0 0 auto",
                backgroundColor: selected ? ACCENT : "transparent",
                color: selected ? "#ffffff" : ACCENT,
                transition:
                  "background-color 0.2s ease, color 0.2s ease, box-shadow 0.2s ease",
                boxShadow: selected ? "none" : undefined,
              }}
              onMouseEnter={(e) => {
                if (!selected) {
                  e.currentTarget.style.backgroundColor = ACCENT_SOFT
                  e.currentTarget.style.color = ACCENT
                }
              }}
              onMouseLeave={(e) => {
                if (!selected) {
                  e.currentTarget.style.backgroundColor = "transparent"
                  e.currentTarget.style.color = ACCENT
                }
              }}
            >
              {TAB_LABELS[id]}
            </button>
          )
        })}
      </Box>

      <div
        role="tabpanel"
        id="brothers-panel-brothers"
        aria-labelledby="brothers-tab-brothers"
        hidden={activeTab !== "brothers"}
      >
        {activeTab === "brothers" && (
          <Flex flexWrap="wrap">
            {brothersList.map((brotherInfo, i) => (
              <Brother key={i} brotherInfo={brotherInfo} />
            ))}
          </Flex>
        )}
      </div>

      <div
        role="tabpanel"
        id="brothers-panel-executive"
        aria-labelledby="brothers-tab-executive"
        hidden={activeTab !== "executive"}
      >
        {activeTab === "executive" && (
          <Flex flexWrap="wrap">
            {data.executiveCommittee.nodes.map((brotherInfo, i) => (
              <LeaderBrother
                key={i}
                name={brotherInfo.Name}
                title={brotherInfo.Title}
              />
            ))}
          </Flex>
        )}
      </div>

      <div
        role="tabpanel"
        id="brothers-panel-directors"
        aria-labelledby="brothers-tab-directors"
        hidden={activeTab !== "directors"}
      >
        {activeTab === "directors" && (
          <Flex flexWrap="wrap">
            {data.directors.nodes.map((brotherInfo, i) => (
              <LeaderBrother
                key={i}
                name={brotherInfo.Name}
                title={brotherInfo.Title}
              />
            ))}
          </Flex>
        )}
      </div>

      <div
        role="tabpanel"
        id="brothers-panel-family"
        aria-labelledby="brothers-tab-family"
        hidden={activeTab !== "family"}
      >
        {activeTab === "family" && (
          <Flex flexWrap="wrap">
            {data.families.nodes.map((family, i) => (
              <FamilyTree key={i} familyName={family.name} />
            ))}
          </Flex>
        )}
      </div>
    </StandardLayout>
  )
}

// 🔥 THIS IS THE IMPORTANT PART (GraphQL)
export const query = graphql`
  {
    executiveCommittee: allLeadershipCurrentdataXlsxSheet1 {
      nodes {
        Name
        Title
      }
    }

    directors: allDirectorsCurrentdataXlsxSheet1 {
      nodes {
        Name
        Title
      }
    }
    brothers: allBiosCurrentdataXlsxFormResponses1 {
      nodes {
        Last_Name
        First_Name
        LinkedIn_URL
        Email
        Class
      }
    }

    families: allFile(
      filter: { sourceInstanceName: { eq: "families" } }
      sort: { fields: name }
    ) {
      nodes {
        name
      }
    }
  }
`
